public class Caja<T> {
    private T contenido;
    public void guardar(T item) { this.contenido = item; }
    public T obtener() { return contenido; }
}

Caja<String> caja = new Caja<>();
caja.guardar("Hola");

public static <T> T primerElemento(List<T> lista) {
    return lista.get(0);
}

public void imprimir(List<?> lista) {
    for (Object o : lista) System.out.println(o);
}

public double sumar(List<? extends Number> nums) {
    double total = 0;
    for (Number n : nums) total += n.doubleValue();
    return total;
}

public void añadirNumeros(List<? super Integer> lista) {
    lista.add(10);
    lista.add(20);
}

